const input = $json.body || $json;
const fotoUsuario = String(input.foto_usuario_base64 || '').trim();
const outfitItems = Array.isArray(input.outfit_items) ? input.outfit_items : [];
const outfitNombre = String(input.outfit_nombre || 'Outfit').trim();

function getMimeAndData(dataUri, fallbackMime = 'image/jpeg') {
  const match = String(dataUri || '').match(/^data:(.*?);base64,(.*)$/);
  if (match) {
    return { mime: match[1] || fallbackMime, data: match[2] || '' };
  }
  return { mime: fallbackMime, data: String(dataUri || '') };
}

if (!fotoUsuario) {
  throw new Error('foto_usuario_base64 vacia');
}

if (outfitItems.length !== 4) {
  throw new Error('outfit_items debe tener exactamente 4 prendas');
}

const sourceUserImage = getMimeAndData(fotoUsuario, 'image/jpeg');
const garmentImages = outfitItems.map((item) => {
  const parsed = getMimeAndData(item.foto_prenda_base64 || '', 'image/jpeg');
  return {
    slot: item.slot,
    mime: parsed.mime,
    data: parsed.data,
    descripcion: String(item.descripcion_prenda || item.pie_foto || '').trim()
  };
});

if (garmentImages.some((g) => !g.data)) {
  throw new Error('Hay prendas sin imagen base64 valida');
}

const garmentHints = garmentImages
  .map((g) => `- Prenda slot ${g.slot}: ${g.descripcion || 'sin descripcion'}`)
  .join('\n');

const systemInstruction = `Eres un editor de imagen de moda. FASE 1: genera un try-on realista del outfit completo sobre la persona de la imagen base. Prioriza pose, cuerpo, proporcion, iluminacion y ropa. Si el rostro cambia ligeramente no importa porque habra una FASE 2 dedicada a restaurar identidad facial exacta.`;

const prompt = `FASE 1 - TRY ON DEL OUTFIT COMPLETO.\n\nUsa la PRIMERA imagen como foto base del usuario de cuerpo entero. Usa las 4 imagenes siguientes como referencias exactas de las prendas del outfit.\n\nOBJETIVO:\n- Mantener cuerpo, pose, encuadre y fondo de la foto original.\n- Aplicar las 4 prendas del outfit de forma coherente y realista.\n- Priorizar realismo de caida, ajuste y combinacion del conjunto.\n- No añadir prendas extra ni accesorios inventados.\n\nOUTFIT: ${outfitNombre}\nDETALLE PRENDAS:\n${garmentHints}`;

const parts = [
  { text: prompt },
  { inline_data: { mime_type: sourceUserImage.mime, data: sourceUserImage.data } }
];

for (const g of garmentImages) {
  parts.push({ inline_data: { mime_type: g.mime, data: g.data } });
}

return [{
  json: {
    sourceUserImage,
    geminiRequest: {
      systemInstruction: {
        parts: [{ text: systemInstruction }]
      },
      contents: [
        {
          role: 'user',
          parts
        }
      ],
      generationConfig: {
        temperature: 0.2,
        topP: 0.85,
        maxOutputTokens: 8192,
        responseModalities: ['IMAGE', 'TEXT']
      }
    }
  }
}];

const raw = $json;
const parts = raw?.candidates?.[0]?.content?.parts || [];
const imagePart = parts.find((p) => p.inlineData?.data) || parts.find((p) => p.inline_data?.data);
const textPart = parts.find((p) => p.text);

const b64 = imagePart?.inlineData?.data || imagePart?.inline_data?.data || '';
const mime = imagePart?.inlineData?.mimeType || imagePart?.inline_data?.mime_type || 'image/png';

if (!b64) {
  throw new Error('Gemini no devolvio imagen en la fase 1 del try-on');
}

return [{
  json: {
    imagen_base_outfit: `data:${mime};base64,${b64}`,
    descripcion_fase_1: String(textPart?.text || '').trim()
  }
}];

const raw = $json;
const parts = raw?.candidates?.[0]?.content?.parts || [];
const imagePart = parts.find((p) => p.inlineData?.data) || parts.find((p) => p.inline_data?.data);
const textPart = parts.find((p) => p.text);

const b64 = imagePart?.inlineData?.data || imagePart?.inline_data?.data || '';
const mime = imagePart?.inlineData?.mimeType || imagePart?.inline_data?.mime_type || 'image/png';
const descripcion = String(textPart?.text || 'Prueba de outfit generada con restauracion facial.').trim();

if (!b64) {
  throw new Error('Gemini no devolvio imagen en la fase 2 de restauracion facial');
}

return [{
  json: {
    imagen_resultado: `data:${mime};base64,${b64}`,
    descripcion
  }
}];
